// Parse Gmail API response and extract email body
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const message = item.json;

    // Extract plain text body from Gmail message
    let emailBody = '';

    if (message.payload && message.payload.parts) {
      // Multi-part email (text + HTML)
      const textPart = message.payload.parts.find(p => p.mimeType === 'text/plain');
      if (textPart && textPart.body && textPart.body.data) {
        emailBody = Buffer.from(textPart.body.data, 'base64').toString('utf-8');
      }
    } else if (message.payload && message.payload.body && message.payload.body.data) {
      // Single-part email
      emailBody = Buffer.from(message.payload.body.data, 'base64').toString('utf-8');
    }

    // Validate extracted email body
    if (!emailBody || emailBody.trim().length === 0) {
      throw new Error('ERR_INSUFFICIENT_DATA: Email has no extractable text content');
    }

    // Extract email headers
    const headers = message.payload.headers || [];
    const getHeader = (name) => {
      const header = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
      return header ? header.value : '';
    };

    // Build normalized output
    results.push({
      json: {
        document_id: $('Fetch Email Content').first().json.document_id,
        document_type: 'email',
        extracted_text: emailBody.trim(),
        extraction_method: 'gmail-api',
        email_subject: getHeader('Subject'),
        email_from: getHeader('From'),
        email_date: getHeader('Date'),
        email_message_id: message.id,
        file_path: $('Fetch Email Content').first().json.file_path || '',
        company_id: $('Fetch Email Content').first().json.company_id,
        supplier_id: $('Fetch Email Content').first().json.supplier_id,
        callback_url: $('Fetch Email Content').first().json.callback_url,
        text_length: emailBody.trim().length,
        processing_timestamp: new Date().toISOString()
      }
    });
  } catch (error) {
    // Handle extraction errors
    results.push({
      json: {
        document_id: $('Fetch Email Content').first().json.document_id,
        document_type: 'email',
        extraction_status: 'error',
        error_code: error.message.includes('ERR_') ? error.message.split(':')[0] : 'ERR_EXTRACTION_FAILED',
        error_message: error.message,
        file_path: $('Fetch Email Content').first().json.file_path || '',
        company_id: $('Fetch Email Content').first().json.company_id,
        supplier_id: $('Fetch Email Content').first().json.supplier_id,
        callback_url: $('Fetch Email Content').first().json.callback_url
      }
    });
  }
}

return results;
